		Data_property ("Data-property", "Property/Data-property", "Something that pertains to data or information.", "HED_0012492")
		Data_artifact ("Data-artifact", "Property/Data-property/Data-artifact", "An anomalous, interfering, or distorting signal originating from a source other than the item being studied.", "HED_0012493")
		Biological_artifact ("Biological-artifact", "Property/Data-property/Data-artifact/Biological-artifact", "A data artifact arising from a biological entity being measured.", "HED_0012494")
		Chewing_artifact ("Chewing-artifact", "Property/Data-property/Data-artifact/Biological-artifact/Chewing-artifact", "Artifact from moving the jaw in a chewing motion.", "HED_0012495")
		ECG_artifact ("ECG-artifact", "Property/Data-property/Data-artifact/Biological-artifact/ECG-artifact", "An electrical artifact from the far-field potential from pulsation of the heart, time locked to QRS complex.", "HED_0012496")
		EMG_artifact ("EMG-artifact", "Property/Data-property/Data-artifact/Biological-artifact/EMG-artifact", "Artifact from muscle activity and myogenic potentials at the measurements site. In EEG, myogenic potentials are the most common artifacts. Frontalis and temporalis muscles (e.g. clenching of jaw muscles) are common causes. Generally, the potentials generated in the muscles are of shorter duration than those generated in the brain. The frequency components are usually beyond 30-50 Hz, and the bursts are arrhythmic.", "HED_0012497")
		Eye_artifact ("Eye-artifact", "Property/Data-property/Data-artifact/Biological-artifact/Eye-artifact", "Ocular movements and blinks can result in artifacts in different types of data. In electrophysiology data, these can result transients and offsets the signal.", "HED_0012498")
		Eye_blink_artifact ("Eye-blink-artifact", "Property/Data-property/Data-artifact/Biological-artifact/Eye-artifact/Eye-blink-artifact", "Artifact from eye blinking. In EEG, Fp1/Fp2 electrodes become electro-positive with eye closure because the cornea is positively charged causing a negative deflection in Fp1/Fp2. If the eye blink is unilateral, consider prosthetic eye.", "HED_0012499")
		Eye_movement_artifact ("Eye-movement-artifact", "Property/Data-property/Data-artifact/Biological-artifact/Eye-artifact/Eye-movement-artifact", "Eye movements can cause artifacts on recordings. The charge of the eye can especially cause artifacts in electrophysiology data.", "HED_0012500")
		Horizontal_eye_movement_artifact ("Horizontal-eye-movement-artifact", "Property/Data-property/Data-artifact/Biological-artifact/Eye-artifact/Eye-movement-artifact/Horizontal-eye-movement-artifact", "Artifact from moving eyes left-to-right and right-to-left. In EEG, there is an upward deflection in the Fp2-F8 derivation, when the eyes move to the right side. In this case F8 becomes more positive and therefore. When the eyes move to the left, F7 becomes more positive and there is an upward deflection in the Fp1-F7 derivation.", "HED_0012501")
		Nystagmus_artifact ("Nystagmus-artifact", "Property/Data-property/Data-artifact/Biological-artifact/Eye-artifact/Eye-movement-artifact/Nystagmus-artifact", "Artifact from nystagmus (a vision condition in which the eyes make repetitive, uncontrolled movements).", "HED_0012502")
		Slow_eye_movement_artifact ("Slow-eye-movement-artifact", "Property/Data-property/Data-artifact/Biological-artifact/Eye-artifact/Eye-movement-artifact/Slow-eye-movement-artifact", "Artifacts originating from slow, rolling eye-movements, seen during drowsiness.", "HED_0012503")
		Vertical_eye_movement_artifact ("Vertical-eye-movement-artifact", "Property/Data-property/Data-artifact/Biological-artifact/Eye-artifact/Eye-movement-artifact/Vertical-eye-movement-artifact", "Artifact from moving eyes up and down. In EEG, this causes positive potentials (50-100 micro V) with bi-frontal distribution, maximum at Fp1 and Fp2, when the eyeball rotates upward. The downward rotation of the eyeball is associated with the negative deflection. The time course of the deflections is similar to the time course of the eyeball movement.", "HED_0012504")
		Movement_artifact ("Movement-artifact", "Property/Data-property/Data-artifact/Biological-artifact/Movement-artifact", "Artifact in the measured data generated by motion of the subject.", "HED_0012505")
		Pulse_artifact ("Pulse-artifact", "Property/Data-property/Data-artifact/Biological-artifact/Pulse-artifact", "A mechanical artifact from a pulsating blood vessel near a measurement site, cardio-ballistic artifact.", "HED_0012506")
		Respiration_artifact ("Respiration-artifact", "Property/Data-property/Data-artifact/Biological-artifact/Respiration-artifact", "Artifact from breathing.", "HED_0012507")
		Rocking_patting_artifact ("Rocking-patting-artifact", "Property/Data-property/Data-artifact/Biological-artifact/Rocking-patting-artifact", "Quasi-rhythmical artifacts in recordings most commonly seen in infants. Typically caused by a caregiver rocking or patting the infant.", "HED_0012508")
		Sucking_artifact ("Sucking-artifact", "Property/Data-property/Data-artifact/Biological-artifact/Sucking-artifact", "Artifact from sucking, typically seen in very young cases.", "HED_0012509")
		Sweat_artifact ("Sweat-artifact", "Property/Data-property/Data-artifact/Biological-artifact/Sweat-artifact", "Artifact from sweating. In EEG, this is a low amplitude undulating waveform that is usually greater than 2 seconds and may appear to be an unstable baseline.", "HED_0012510")
		Tongue_movement_artifact ("Tongue-movement-artifact", "Property/Data-property/Data-artifact/Biological-artifact/Tongue-movement-artifact", "Artifact from tongue movement (Glossokinetic). The tongue functions as a dipole, with the tip negative with respect to the base. In EEG, the artifact produced by the tongue has a broad potential field that drops from frontal to occipital areas, although it is less steep than that produced by eye movement artifacts. The amplitude of the potentials is greater inferiorly than in parasagittal regions; the frequency is variable but usually in the delta range. Chewing and sucking can produce similar artifacts.", "HED_0012511")
		Nonbiological_artifact ("Nonbiological-artifact", "Property/Data-property/Data-artifact/Nonbiological-artifact", "A data artifact arising from a non-biological source.", "HED_0012512")
		Artificial_ventilation_artifact ("Artificial-ventilation-artifact", "Property/Data-property/Data-artifact/Nonbiological-artifact/Artificial-ventilation-artifact", "Artifact stemming from mechanical ventilation. These can occur at the same rate as the ventilator, but also have other patterns.", "HED_0012513")
		Dialysis_artifact ("Dialysis-artifact", "Property/Data-property/Data-artifact/Nonbiological-artifact/Dialysis-artifact", "Artifacts seen in recordings during continuous renal replacement therapy (dialysis).", "HED_0012514")
		Electrode_movement_artifact ("Electrode-movement-artifact", "Property/Data-property/Data-artifact/Nonbiological-artifact/Electrode-movement-artifact", "Artifact from electrode movement.", "HED_0012515")
		Electrode_pops_artifact ("Electrode-pops-artifact", "Property/Data-property/Data-artifact/Nonbiological-artifact/Electrode-pops-artifact", "Brief artifact with a steep rise and slow fall of an electrophysiological signal, most often caused by a loose electrode.", "HED_0012516")
		Induction_artifact ("Induction-artifact", "Property/Data-property/Data-artifact/Nonbiological-artifact/Induction-artifact", "Artifacts induced by nearby equipment. In EEG, these are usually of high frequency.", "HED_0012517")
		Line_noise_artifact ("Line-noise-artifact", "Property/Data-property/Data-artifact/Nonbiological-artifact/Line-noise-artifact", "Power line noise at 50 Hz or 60 Hz.", "HED_0012518")
		Line_noise_artifact_value ("Line-noise-artifact-#", "Property/Data-property/Data-artifact/Nonbiological-artifact/Line-noise-artifact/Line-noise-artifact-#", "", "HED_0012519")
		Salt_bridge_artifact ("Salt-bridge-artifact", "Property/Data-property/Data-artifact/Nonbiological-artifact/Salt-bridge-artifact", "Artifact from salt-bridge between EEG electrodes.", "HED_0012520")	
